{"type": "email", "id": "email_002", "subject": "EV Industry Conference", "from": "sarah.jones@elexionautomotive.com", "from_name": "Sarah Jones", "to": ["amanda.foster@elexionautomotive.com", "peter.martin@elexionautomotive.com"], "cc": [], "date": "2023-06-21 09:30:00", "body": "Hi Amanda and Peter,

