{"type": "email", "id": "email_004", "subject": "Software Update Implementation", "from": "tom.parker@elexionautomotive.com", "from_name": "Tom Parker", "to": ["amanda.foster@elexionautomotive.com"], "cc": ["peter.martin@elexionautomotive.com"], "date": "2023-06-22 14:00:00", "body": "Hi Amanda,

